package dev.langchain4j.model.scoring.onnx;

import ai.onnxruntime.OrtSession;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

import java.io.IOException;
import java.net.URL;
import java.nio.file.Files;
import java.nio.file.Path;

import static java.nio.file.StandardCopyOption.REPLACE_EXISTING;
import static org.assertj.core.api.Assertions.assertThat;
import static org.junit.jupiter.api.Assertions.assertDoesNotThrow;

class OnnxScoringModelCloseTest {

    @TempDir
    private static Path tempDir;

    @Test
    void should_implement_auto_closeable() throws IOException {
        URL modelUrl = new URL("https://huggingface.co/Xenova/ms-marco-MiniLM-L-6-v2/resolve/main/onnx/model_quantized.onnx?download=true");
        Path modelPath = tempDir.resolve("model_quantized_close_test.onnx");
        Files.copy(modelUrl.openStream(), modelPath, REPLACE_EXISTING);

        URL tokenizerUrl = new URL("https://huggingface.co/Xenova/ms-marco-MiniLM-L-6-v2/resolve/main/tokenizer.json?download=true");
        Path tokenizerPath = tempDir.resolve("tokenizer_close_test.json");
        Files.copy(tokenizerUrl.openStream(), tokenizerPath, REPLACE_EXISTING);

        OnnxScoringModel model = new OnnxScoringModel(modelPath.toString(), new OrtSession.SessionOptions(), tokenizerPath.toString(), 512, false);

        // Verify it implements AutoCloseable
        assertThat(model).isInstanceOf(AutoCloseable.class);

        // Verify close() doesn't throw
        assertDoesNotThrow(() -> model.close());
    }

    @Test
    void should_close_via_try_with_resources() throws IOException {
        URL modelUrl = new URL("https://huggingface.co/Xenova/ms-marco-MiniLM-L-6-v2/resolve/main/onnx/model_quantized.onnx?download=true");
        Path modelPath = tempDir.resolve("model_quantized_try_test.onnx");
        Files.copy(modelUrl.openStream(), modelPath, REPLACE_EXISTING);

        URL tokenizerUrl = new URL("https://huggingface.co/Xenova/ms-marco-MiniLM-L-6-v2/resolve/main/tokenizer.json?download=true");
        Path tokenizerPath = tempDir.resolve("tokenizer_try_test.json");
        Files.copy(tokenizerUrl.openStream(), tokenizerPath, REPLACE_EXISTING);

        // Try-with-resources should work
        try (OnnxScoringModel model = new OnnxScoringModel(modelPath.toString(), new OrtSession.SessionOptions(), tokenizerPath.toString(), 512, false)) {
            assertThat(model).isNotNull();
        }
        // If we got here, close() was called successfully via try-with-resources
    }
}

